export default function AddMoneyOptionsScreen({ onBack, onSelectOption }) {
  const options = [
    { id: "card", title: "Debit Card" },
    { id: "bank", title: "Bank Transfer" },
  ];

  return (
    <div className="px-6 pt-6">
      <button onClick={onBack}>← Back</button>

      <h1 className="text-xl font-bold mb-6">Add Money</h1>

      <div className="space-y-4">
        {options.map((opt) => (
          <button
            key={opt.id}
            onClick={() => onSelectOption(opt)}
            className="w-full p-4 rounded-xl bg-white border text-left"
          >
            {opt.title}
          </button>
        ))}
      </div>
    </div>
  );
}
